  });

  it('round-trips search routes through toSearchHash -> parseHash', () => {
    const cases: Array<[string, string]> = [
      ['', ''],
      ['hello', 'docs'],
      ['hello world', 'my docs'],
      ['a&b', 'c=d'],
    ];
    for (const [query, path] of cases) {
      expect(parseHash(toSearchHash(query, path))).toEqual({ view: 'search', query, path });
    }
  });

  it('produces view values that are valid View union members', () => {
    const views: View[] = [
      parseHash(toBrowseHash('docs')).view,
      parseHash(toSearchHash('q', 'p')).view,
    ];
    expect(views).toEqual(['browse', 'search']);
  });
});

describe('getCurrentRoute', () => {
  beforeEach(() => {
    window.location.hash = '';
  });

  it('returns the default browse route when the hash is empty', () => {
    expect(getCurrentRoute()).toEqual({ view: 'browse', path: '', query: '' });
  });

  it('parses the current browse hash from window.location', () => {
    window.location.hash = '#/browse/docs/2024';
    expect(getCurrentRoute()).toEqual({ view: 'browse', path: 'docs/2024', query: '' });
