  it('updates the hash so getCurrentRoute reflects the new route', () => {
    navigate('#/search?q=hi&path=x');
    expect(getCurrentRoute()).toEqual({ view: 'search', query: 'hi', path: 'x' });
  });
});

describe('subscribe', () => {
  const unsubs: Array<() => void> = [];

  beforeEach(() => {
    window.location.hash = '';
  });

  afterEach(() => {
    let unsub: (() => void) | undefined;
    while ((unsub = unsubs.pop()) !== undefined) {
      unsub();
    }
  });

  it('invokes the callback on hashchange events', () => {
    const cb = vi.fn();
    unsubs.push(subscribe(cb));

    window.dispatchEvent(new Event('hashchange'));

    expect(cb).toHaveBeenCalledTimes(1);
  });

  it('returns an unsubscribe function that removes the listener', () => {
    const cb = vi.fn();
    const unsub = subscribe(cb);
    unsubs.push(unsub);

    window.dispatchEvent(new Event('hashchange'));
    expect(cb).toHaveBeenCalledTimes(1);

    unsub();

    window.dispatchEvent(new Event('hashchange'));
    window.dispatchEvent(new Event('hashchange'));
    expect(cb).toHaveBeenCalledTimes(1);
  });

  it('supports multiple independent subscriptions', () => {
    const cb1 = vi.fn();
    const cb2 = vi.fn();
    const unsub1 = subscribe(cb1);
    unsubs.push(unsub1);
    unsubs.push(subscribe(cb2));

    window.dispatchEvent(new Event('hashchange'));
    expect(cb1).toHaveBeenCalledTimes(1);
    expect(cb2).toHaveBeenCalledTimes(1);

    unsub1();

    window.dispatchEvent(new Event('hashchange'));
    expect(cb1).toHaveBeenCalledTimes(1);
    expect(cb2).toHaveBeenCalledTimes(2);
  });
